//   python3 util/vial_generate_keyboard_uid.py
//
#define VIAL_KEYBOARD_UID {0x93, 0x1A, 0xE4, 0x27, 0xC7, 0x1B, 0xFB, 0x47}

// ── VIAL SECURITY UNLOCK COMBO ───────────────────────────────────
// Vial requires you to hold a key combination to "unlock" the keyboard
// for programming. This protects against malicious USB hosts reprogramming
// your keyboard without your knowledge.
//
// Current combo: top-left key [row 0, col 0] + bottom-right key [row 2, col 2]
// Hold both keys simultaneously when Vial prompts for unlock.
//
// To change: replace the row/col numbers below with any 2+ keys
// that appear in your layout. Row and col are zero-based matrix positions.
//
#define VIAL_UNLOCK_COMBO_ROWS { 0, 2 }
#define VIAL_UNLOCK_COMBO_COLS { 0, 2 }


